                {"speaker": "You", "swissGerman": "Merci vilmal! Ich beeile mich.", "german": "Vielen Dank! Ich beeile mich.", "english": "Thank you so much! I'll hurry.", "spanish": "¡Muchas gracias! Me doy prisa."},
                {"speaker": "Receptionist", "swissGerman": "Chömed Si denn direkt zum Schalter — Si müend sich nöd nochmals aamelda.", "german": "Kommen Sie dann direkt zum Schalter — Sie müssen sich nicht noch einmal anmelden.", "english": "Come straight to the desk — you don't need to register again.", "spanish": "Ven directamente al mostrador — no necesitas registrarte de nuevo."},
                {"speaker": "You", "swissGerman": "Oh, perfekt. Das sparche mir Ziit. Merci!", "german": "Oh, perfekt. Das spart uns Zeit. Danke!", "english": "Oh, perfect. That saves us time. Thanks!", "spanish": "¡Oh, perfecto! Eso nos ahorra tiempo. ¡Gracias!"},
